public int binaryGap(int n) {
    int maxGap = 0;
    int lastOne = -1;

    for (int i = 0; i < 32; i++) {
        if ((n & (1 << i)) != 0) {
            if (lastOne != -1) {
                maxGap = Math.max(maxGap, i - lastOne);
            }
            lastOne = i;
        }
    }

    return maxGap;
}

