def binary_gap(n: int) -> int:
    max_gap = 0
    last_one = -1
    i = 0
    while n:
        if n & 1:
            if last_one != -1:
                max_gap = max(max_gap, i - last_one)
            last_one = i
        n >>= 1
        i += 1
    return max_gap
